#!/usr/bin/env python3
# AUTHORIZED LAB ONLY (127.0.0.1). Demonstrates token-replay trust failure: a verifier that
# trusts issuer-only accepts a captured bearer token presented from a different client.
# No real IdP, no third-party tokens, FAKE signing key.
import base64, hmac, hashlib, json, time, threading, urllib.request
from flask import Flask, request

FAKE_KEY = b'LAB-FAKE-HS256-KEY-do-not-use'
app = Flask(__name__)

def b64u(b):
    return base64.urlsafe_b64encode(b).rstrip(b'=').decode()

def mint(sub):
    hdr = b64u(json.dumps({'alg':'HS256','typ':'JWT'}).encode())
    pl  = b64u(json.dumps({'iss':'lab-idp','sub':sub,'iat':int(time.time())}).encode())
    sig = b64u(hmac.new(FAKE_KEY, (hdr+'.'+pl).encode(), hashlib.sha256).digest())
    return hdr+'.'+pl+'.'+sig

@app.route('/resource')
def resource():
    tok = request.headers.get('Authorization','').replace('Bearer ','')
    try:
        hdr,pl,sig = tok.split('.')
        exp = b64u(hmac.new(FAKE_KEY,(hdr+'.'+pl).encode(),hashlib.sha256).digest())
        if not hmac.compare_digest(exp,sig):
            return 'SIG-FAIL',401
        claims = json.loads(base64.urlsafe_b64decode(pl+'=='))
        # SEAM ON PURPOSE: only the issuer is checked. No aud, no exp, no sender-binding (DPoP/mTLS).
        if claims.get('iss')=='lab-idp':
            return 'ACCESS-GRANTED sub=%s' % claims['sub']
        return 'ISS-FAIL',401
    except Exception as e:
        return 'ERR %s'%e,400

def serve():
    app.run(host='127.0.0.1',port=7001,use_reloader=False)

if __name__=='__main__':
    threading.Thread(target=serve,daemon=True).start(); time.sleep(1.5)
    captured = mint('operator')  # token from the operator's OWN session
    print('[*] captured token (own session):', captured[:40]+'...')
    # Replay from a 'different' client context — same token, no binding stops it
    req = urllib.request.Request('http://127.0.0.1:7001/resource', headers={'Authorization':'Bearer '+captured})
    print('replay result:', urllib.request.urlopen(req).read().decode())

