#!/usr/bin/env python3
# AUTHORIZED LAB ONLY. Spray demo against a LOCAL auth stub (no real DC/IdP, no third parties).
# Lockout-aware pacing: 1 try/account/round, sleep between rounds. Shows weak-cred + spray pattern.
import time

# Local stub user store (FAKE). One user has a weak password = the seam.
USERS = {'alice':'S3curePass!93x','bob':'Winter2026$rnd','svc_app':'Password1','carol':'q9$Lm2Vt'}
LOCKOUT_THRESHOLD = 5          # lab policy
ROUND_PACING_SECONDS = 0.2     # shortened for demo; real spray paces under observation window

def auth_stub(user, pwd):
    return USERS.get(user) == pwd

SPRAY = ['Password1','Spring2026!','Welcome1!']  # common-weak candidates
failures = {u:0 for u in USERS}
hit = None
for pwd in SPRAY:
    print('[*] spraying password #%s across %d accounts' % (SPRAY.index(pwd)+1, len(USERS)))
    for u in USERS:
        if failures[u] >= LOCKOUT_THRESHOLD-1:   # lockout-aware: skip near-threshold accounts
            continue
        if auth_stub(u, pwd):
            hit = (u, pwd); break
        failures[u]+=1
    if hit: break
    time.sleep(ROUND_PACING_SECONDS)

if hit:
    print('RESULT: WEAK CRED FOUND -> %s : %s (seam: weak/predictable password accepted)' % hit)
else:
    print('RESULT: no weak cred in candidate set')
print('[*] failed-attempt counts (drives 4625 burst signature):', failures)
